INSERT INTO "Testimonial" ("id", "name", "school", "content", "avatar", "rating", "order", "createdAt", "updatedAt") VALUES ('testimonial-1', 'Nguyễn Minh Châu', 'Đại học Phúc Đán, Thượng Hải', 'NOVAPATH hỗ trợ tôi từ A-Z: từ chọn trường, dịch hồ sơ đến xin học bổng CSC 100%. Giờ tôi đang học năm 2 tại Phúc Đán — ước mơ thành sự thật!', 'https://images.unsplash.com/photo-1494790108755-2616b612b786?w=100&q=80', 5, 1, '2026-06-05T03:44:49.874Z', '2026-06-05T03:44:49.874Z');
INSERT INTO "Testimonial" ("id", "name", "school", "content", "avatar", "rating", "order", "createdAt", "updatedAt") VALUES ('testimonial-2', 'Trần Hoàng Anh', 'Đại học Đồng Tế, Thượng Hải', 'Tôi lo ngại về rào cản ngôn ngữ, nhưng đội ngũ NOVAPATH tư vấn lộ trình tiếng Trung rất rõ ràng. Hiện tôi đã đạt HSK 4 và tự tin giao tiếp hàng ngày.', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=100&q=80', 5, 2, '2026-06-05T03:44:49.881Z', '2026-06-05T03:44:49.881Z');
INSERT INTO "Testimonial" ("id", "name", "school", "content", "avatar", "rating", "order", "createdAt", "updatedAt") VALUES ('testimonial-3', 'Lê Thị Thu Hà', 'Đại học Ngôn ngữ Bắc Kinh', 'Chi phí du học tôi tiết kiệm được hơn 60% nhờ học bổng mà NOVAPATH giúp tìm kiếm. Quy trình nộp hồ sơ nhanh, minh bạch, không phát sinh chi phí ẩn.', 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=100&q=80', 5, 3, '2026-06-05T03:44:49.889Z', '2026-06-05T03:44:49.889Z');
